@bs:{ env ="BS" int }
seq:10
let x = _;

# A bare `continue` should re-enter the loop with the updated binding when the
# body only mutates one loop-local binding.
loop {
	if x < 3 {
		set x = x + 1
		continue
	}
	sum
	break
}


